 penggel","nasi pindang","nasi polok","nasi pulut","nasi punar","nasi pundut","nasi punel","nasi punten","nasi putih","nasi rames","nasi rawon","nasi rogoh","nasi rumo","nasi sakapal","nasi samin","nasi sega","nasi sek","nasi serpang","nasi siram","nasi sodu","nasi subut","nasi suci ulam sari","nasi suci ulam sari (2)","nasi sumsum","nasi tambakan","nasi tela","nasi tepeng","nasi tim","nasi timbel","nasi tue","nasi tumpang","nasi tumpeng","nasi tungkus","nasi tutug oncom","nasi uceng","nasi uduk","nasi ulam","nasi wadang"]', '["ada hari, ada nasi","ada nasi di balik kerak","air diminum rasa duri, nasi dimakan rasa sekam","anjing diberi makan nasi bilakan kenyang","habis perkara, nasi sudah menjadi bubur","harap nasi, tak harap tanak","kerak nasi membusut jantan","kuah tumpah (tertuang) ke nasi","lagi lauk, lagi nasi","membesarkan kerak nasi","nasi habis, budi bersua","nasi sama ditanak, kerak dimakan seorang","nasi sudah menjadi bubur","nasi tersaji di lutut","nasi tersendok tidak termakan","orang haus diberi air, orang lapar diberi nasi","pinggan tak retak, nasi tak dingin","sambil berdiang, nasi masak","sendok berdengar-dengar, nasi habis budi dapat"]', '["mencari sesuap nasi","nasi kosong","terkunyah di nasi"]', '[{"peribahasa":"ada hari, ada nasi","makna":"Selama masih hidup, seseorang pasti akan mendapatkan rezeki."},{"peribahasa":"ada nasi di balik kerak","makna":"Masih ada maksud atau tujuan tersembunyi di balik suatu perbuatan atau perkataan."},{"peribahasa":"air diminum rasa duri, nasi dimakan rasa sekam","makna":"Sangat sedih atau berduka cita sehingga tidak enak makan dan minum."},{"peribahasa":"anjing diberi makan nasi bilakan kenyang","makna":"Memberi nasihat atau bantuan kepada orang yang tidak tahu berterima kasih adalah sia-sia."},{"peribahasa":"habis perkara, nasi sudah menjadi bubur","makna":"Sesuatu yang sudah terlanjur terjadi tidak dapat diubah kembali."},{"peribahasa":"harap nasi, tak harap tanak","makna":"Hanya menginginkan hasilnya tanpa mau berusaha."},{"peribahasa":"kerak nasi membusut jantan","makna":"Seseorang yang sombong karena kekayaan atau kedudukan yang baru diperolehnya."},{"peribahasa":"kuah tumpah (tertuang) ke nasi","makna":"Sesuatu yang kembali kepada pemiliknya atau tempat asalnya."},{"peribahasa":"lagi lauk, lagi nasi","makna":"Semakin banyak kekayaan atau keuntungan, semakin besar pula keinginan untuk menambahnya."},{"peribahasa":"membesarkan kerak nasi","makna":"Menambah-nambah masalah yang sudah ada."},{"peribahasa":"nasi habis, budi bersua","makna":"Setelah pertolongan atau kebaikan tidak lagi diberikan, barulah sifat asli seseorang terlihat."},{"peribahasa":"nasi sama ditanak, kerak dimakan seorang","makna":"Bekerja sama-sama, tetapi keuntungan dinikmati sendiri."},{"peribahasa":"nasi sudah menjadi bubur","makna":"Sesuatu yang sudah terlanjur terjadi dan tidak dapat diubah kembali."},{"peribahasa":"nasi tersaji di lutut","makna":"Mendapatkan rezeki atau keuntungan dengan sangat mudah."},{"peribahasa":"nasi tersendok tidak termakan","makna":"Sesuatu yang sudah hampir didapatkan tetapi akhirnya gagal."},{"peribahasa":"orang haus diberi air, orang lapar diberi nasi","makna":"Memberikan pertolongan kepada orang yang sangat membutuhkannya."},{"peribahasa":"pinggan tak retak, nasi tak dingin","makna":"Melakukan pekerjaan dengan sangat hati-hati dan cermat."},{"peribahasa":"sambil berdiang, nasi masak","makna":"Melakukan dua pekerjaan sekaligus."},{"peribahasa":"sendok berdengar-dengar, nasi habis budi dapat","makna":"Kebaikan atau pertolongan yang diberikan dengan mengharapkan imbalan atau pujian."}]');
