insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('56666', 'ne.ge.ri', 'negeri', '', '', '["Nomina","Nomina","Nomina","Nomina","Nomina","Melayu Ambon"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"tanah tempat tinggal suatu bangsa","contoh":[{"nomor":2,"teks":"ia melanjutkan sekolah ke -- Belanda"}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"kampung halaman; tempat kelahiran","contoh":[{"nomor":2,"teks":"--nya yang asli bukanlah Makassar"}]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"negara; pemerintah (lawan kata swasta)","contoh":[{"nomor":2,"teks":"karena ia bersekolah di SMA --, biayanya pun tidak begitu besar"}]},{"nomor":"4","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"nagari","contoh":[]},{"nomor":"5","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"MAb","nama":"Melayu Ambon","tipe":"lainnya"}],"definisi":"kesatuan masyarakat hukum adat yang memiliki batas wilayah, berwenang untuk mengurus urusan pemerintahan dan kepentingan masyarakat setempat berdasarkan prakarsa masyarakat, hak asal-usul, dan/atau hak tradisional yang diakui dan dihormati dalam sistem pemerintahan Negara Kesatuan Republik Indonesia","contoh":[]}]', null, '["kenegerian","penegerian"]', '["negeri antah berantah","negeri Atap Dunia","negeri atas angin","negeri awak","negeri bawah angin","negeri Beruang Merah","negeri Di Atas Awan","negeri Gajah Putih","negeri Ginseng","negeri jiran","negeri Kanguru","negeri keju","negeri Kincir Angin","negeri Kiwi","negeri Kuntum Mawar","negeri Lumbung Padi","negeri Matador","negeri Matahari Terbit","negeri Naga Guntur","negeri orang","negeri Paman Sam","negeri Panser","Negeri Pantun","negeri Piza","negeri ramal","negeri Sakura","negeri Samba","negeri seribu candi","negeri seribu danau","negeri seribu gajah","negeri Seribu Kuil","negeri Seribu Megalit","negeri seribu pagoda","negeri seribu pulau","negeri Seribu Satu Malam","negeri Sombrero","negeri Spageti","negeri Tango","negeri Tirai Bambu","negeri Tirai Besi","negeri upeti"]', '["adat bernegeri memagar negeri, adat berkampung memagar kampung","apa gunanya bulan terang di dalam hutan, jikalau di dalam negeri betapa baiknya","ayam bertelur sebutir, ribut seluruh negeri, penyu bertelur beribu-ribu, tiada seorang pun (yang) tahu","coba-coba menanam mumbang, kalau tumbuh sunting negeri","hujan emas di negeri orang, hujan batu di negeri sendiri, baik jua di negeri sendiri","hujan keris lembing di negeri kita, hujan emas perak di negeri orang, baik jua di negeri kita","kasihkan anak tangan-tangankan, kasihkan bini tinggal-tinggalkan (sayang di anak dibenci, sayang di negeri ditinggalkan)","membawakan cupak ke negeri orang","raja negeri raja pasak, raja adat raja agama","sayang di anak dilecuti, sayang di negeri ditinggalkan","sia-sia negeri alah","tegak adat berpagar adat, tegak suku berpagar suku, tegak kampung berpagar kampung, tegak negeri berpagar negeri","tegak adat berpagar adat, tegak suku berpagar suku, tegak negeri berpagar negeri, tegak bangsa berpagar bangsa"]', '["negeri (alam) yang baka"]', '[{"peribahasa":"adat bernegeri memagar negeri, adat berkampung memagar kampung","makna":"Setiap tempat memiliki aturan dan adat istiadatnya sendiri yang harus dihormati dan dijaga."},{"peribahasa":"apa gunanya bulan terang di dalam hutan, jikalau di dalam negeri betapa baiknya","makna":"Ilmu atau kepandaian tidak akan berguna jika tidak dimanfaatkan untuk kepentingan masyarakat."},{"peribahasa":"ayam bertelur sebutir, ribut seluruh negeri, penyu bertelur beribu-ribu, tiada seorang pun (yang) tahu","makna":"Orang yang berbuat sedikit kebaikan sering kali menyombongkan diri, sementara orang yang berbuat banyak kebaikan justru diam saja."},{"peribahasa":"coba-coba menanam mumbang, kalau tumbuh sunting negeri","makna":"Mencoba melakukan suatu usaha yang tampaknya mustahil atau kecil, dengan harapan jika berhasil akan mendatangkan keuntungan atau kemuliaan yang besar."},{"peribahasa":"hujan emas di negeri orang, hujan batu di negeri sendiri, baik jua di negeri sendiri","makna":"Meskipun negeri orang lain tampak lebih makmur dan menyenangkan, negeri sendiri tetap lebih baik."},{"peribahasa":"hujan keris lembing di negeri kita, hujan emas perak di negeri orang, baik jua di negeri kita","makna":"Meskipun negeri sendiri penuh dengan kesulitan dan bahaya, sedangkan negeri orang lain tampak makmur, negeri sendiri tetap lebih baik."},{"peribahasa":"kasihkan anak tangan-tangankan, kasihkan bini tinggal-tinggalkan (sayang di anak dibenci, sayang di negeri ditinggalkan)","makna":"Terkadang, untuk kebaikan orang yang kita sayangi, kita harus rela berpisah atau bersikap tegas."},{"peribahasa":"membawakan cupak ke negeri orang","makna":"Mengajarkan adat atau kebiasaan sendiri kepada orang lain yang sudah memiliki adatnya sendiri."},{"peribahasa":"raja negeri raja pasak, raja adat raja agama","makna":"Setiap pemimpin memiliki kekuasaan dan tanggung jawabnya masing-masing."},{"peribahasa":"sayang di anak dilecuti, sayang di negeri ditinggalkan","makna":"Terkadang, untuk kebaikan orang yang kita sayangi, kita harus rela bersikap tegas atau berpisah."},{"peribahasa":"sia-sia negeri alah","makna":"Negeri yang hancur karena tidak ada pemimpin yang cakap."},{"peribahasa":"tegak adat berpagar adat, tegak suku berpagar suku, tegak kampung berpagar kampung, tegak negeri berpagar negeri","makna":"Setiap kelompok masyarakat memiliki aturan dan adat istiadatnya sendiri yang harus dijaga dan dihormati."},{"peribahasa":"tegak adat berpagar adat, tegak suku berpagar suku, tegak negeri berpagar negeri, tegak bangsa berpagar bangsa","makna":"Setiap kelompok masyarakat, dari yang terkecil hingga terbesar, memiliki aturan dan adat istiadatnya sendiri yang harus dijaga dan dihormati."}]');
